// Gradient Descent for f(x,y) = x² + y²
function gradientDescent(x0, y0, alpha, maxIter):
 x = x0
 y = y0
 FOR i = 1 to maxIter:
 // Compute partial derivatives
 grad_x = 2*x // ∂f/∂x
 grad_y = 2*y // ∂f/∂y

 // Update in negative gradient direction
 x = x - alpha * grad_x
 y = y - alpha * grad_y

 // Check convergence
 IF |grad_x| < epsilon AND |grad_y| < epsilon:
 BREAK
 RETURN (x, y)

// Newton-Raphson Method for 2D
function newtonRaphson(x0, y0, epsilon, maxIter):
 x = x0
 y = y0

 FOR i = 1 to maxIter:
 // Compute gradient vector
 g = [fx(x,y), fy(x,y)] // [2x, 2y]

 // Compute Hessian matrix
 H = [[fxx(x,y), fxy(x,y)],
 [fxy(x,y), fyy(x,y)]] // [[2, 0], [0, 2]]

 // Solve H * delta = -g for delta
 delta = solveLinearSystem(H, -g)

 // Update
 x = x + delta[0]
 y = y + delta[1]

 IF norm(g) < epsilon:
 BREAK

 RETURN (x, y)

// Find extremum of f(x,y) subject to g(x,y)=0
// Example: f = x+y, g = x² + y² - 1

function lagrangeSolver():
 // Solve system:
 // ∂L/∂x = fx - λ * gx = 0
 // ∂L/∂y = fy - λ * gy = 0 
 // ∂L/∂λ = g(x,y) = 0

 // For f = x+y: fx=1, fy=1
 // For g = x²+y²-1: gx=2x, gy=2y

 // Equations become:
 // 1 = λ * 2x → x = 1/(2λ)
 // 1 = λ * 2y → y = 1/(2λ)
 // x² + y² = 1

 lambda = sqrt(3)/2
 x = 1/(2*lambda) // 1/√3
 y = 1/(2*lambda) // 1/√3

 // Check constraint: x² + y² = 1/3 + 1/3 = 2/3 ≠ 1
 // Need to solve properly:
 // 3/(4λ²) = 1 → λ² = 3/4 → λ = ±√3/2

 RETURN (x, y, lambda)
